import { describe, expect, test } from "bun:test";
import { bytesToBase64, fileToBase64 } from "./file-encoding";
describe("bytesToBase64", () => {
    test("round-trips small payloads", () => {
        const bytes = new Uint8Array([0, 1, 2, 127, 128, 250, 255]);
        expect(atob(bytesToBase64(bytes))).toBe(String.fromCharCode(...bytes));
    });
    test("handles the empty payload", () => {
        expect(bytesToBase64(new Uint8Array(0))).toBe("");
    });
    test("encodes a phone-photo-sized payload correctly", () => {
        const bytes = new Uint8Array(4 * 1024 * 1024);
        for (let i = 0; i < bytes.length; i++) {
            bytes[i] = i % 256;
        }
        const decoded = atob(bytesToBase64(bytes));
        expect(decoded.length).toBe(bytes.length);
        expect(decoded.charCodeAt(0)).toBe(0);
        expect(decoded.charCodeAt(123_457)).toBe(123_457 % 256);
        expect(decoded.charCodeAt(bytes.length - 1)).toBe((bytes.length - 1) % 256);
    });
    test("fallback path (engine without toBase64) matches the default path", () => {
        // Phone-photo-sized so the fallback's chunking is exercised for real,
        // with a length that is not a multiple of the chunk size.
        const bytes = new Uint8Array(4 * 1024 * 1024 + 3);
        for (let i = 0; i < bytes.length; i++) {
            bytes[i] = (i * 7) % 256;
        }
        const legacy = new Uint8Array(bytes);
        Object.defineProperty(legacy, "toBase64", { value: undefined });
        expect(bytesToBase64(legacy)).toBe(bytesToBase64(bytes));
        expect(atob(bytesToBase64(legacy)).length).toBe(bytes.length);
    });
});
describe("fileToBase64", () => {
    test("reads a Blob into the inference image shape", async () => {
        const payload = new Uint8Array([137, 80, 78, 71]);
        const { dataBase64, mimeType } = await fileToBase64(new Blob([payload], { type: "image/png" }));
        expect(mimeType).toBe("image/png");
        expect(atob(dataBase64)).toBe(String.fromCharCode(...payload));
    });
    test("falls back to octet-stream when the Blob carries no type", async () => {
        const { mimeType } = await fileToBase64(new Blob([new Uint8Array([1])]));
        expect(mimeType).toBe("application/octet-stream");
    });
});
